import React, { useState, useRef } from "react";
import { Link } from "react-router-dom";
import "../styles/News.css";
import ReadMore from "./ReadMore";  
import NewsCard from "./NewsCard";  

const articles = [
  {
    id: 1,
    title:
      "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORT LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/news1.jpg",
    description:
      "The key to a successful criminal law enforcement depends on the evidence that has been...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 2,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news2.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 3,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
];

const News = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState(null);
  const newsSectionRef = useRef(null);

  const openModal = (article) => {
    setSelectedArticle(article);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedArticle(null);
  };

  return (
    <div>
      {/* News Section with Ref */}
      <div ref={newsSectionRef} className="news-section">
        <h2 className="news-title">NEWS & ARTICLES</h2>

        <div className="news-grid">
          {articles.map((article) => (
            <NewsCard key={article.id} article={article} onReadMoreClick={openModal} />
          ))}
        </div>

        <div className="view-more-container">
          <Link 
            to="/more-news"
            className="view-more-btn"
            onClick={() => sessionStorage.setItem("scrollPosition", window.scrollY)}
          >
            View more →
          </Link>
        </div>
      </div>

      {isModalOpen && selectedArticle && (
        <ReadMore 
          selectedArticle={selectedArticle} 
          closeModal={closeModal} 
          newsSectionRef={newsSectionRef}  
        />
      )}
    </div>
  );
};

export default News;
